INSERT INTO facts (id, user_id, key, value, category, is_important, created_at, updated_at)
VALUES
  ('fact-eco-sara-core-identity-summary', 'local-user', 'identity.summary', 'Sara Core is a local and offline-first personal assistant platform organized as a Node.js + TypeScript backend, React + TypeScript frontend, Neon PostgreSQL database and shared contracts in a monorepo.', 'ecosystem:sara-core', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-sara-core-mission', 'local-user', 'identity.mission', 'The platform should evolve incrementally, preserve architecture, and turn local structured data into grounded assistant behavior.', 'ecosystem:sara-core', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-sara-core-runtime', 'local-user', 'runtime.execution-model', 'The current product runs as a local application with backend and frontend in the same monorepo and Neon PostgreSQL as the main persisted store.', 'ecosystem:sara-core', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-sara-core-constraints', 'local-user', 'constraints.change-management', 'The project should avoid unnecessary refactors, avoid recreating architecture, and keep new work aligned to the existing module boundaries.', 'ecosystem:sara-core', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-sara-core-roadmap', 'local-user', 'roadmap.execution-order', 'Recommended execution order is backend grounding first, then real database population, then LLM testing with real context, and only later design refinements.', 'ecosystem:sara-core', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-backend-stack', 'local-user', 'stack.summary', 'The backend uses Node.js, TypeScript, Express, pg (node-postgres), Zod validation, structured logging and modular route/controller/service/repository organization.', 'ecosystem:backend', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-backend-layers', 'local-user', 'architecture.layers', 'Core backend layers are routes, controllers, services, repositories, database, config, middlewares, logging and errors.', 'ecosystem:backend', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-backend-modules', 'local-user', 'architecture.modules', 'Current backend modules include health, facts, tasks, conversation_turns, tool_calls, user_profile, voice and llm.', 'ecosystem:backend', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-backend-database', 'local-user', 'database.primary-store', 'Neon PostgreSQL is the source of truth for current grounding data. Facts and user_profile are the primary stores used by the LLM in this phase.', 'ecosystem:backend', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-backend-contracts', 'local-user', 'contracts.shared-types', 'Shared API contracts live in the shared-types package and should remain aligned between backend and frontend.', 'ecosystem:backend', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-frontend-scope', 'local-user', 'scope.current-navigation', 'The frontend is intentionally simplified for this phase and focuses on voice validation and debug visibility instead of broad product navigation.', 'ecosystem:frontend', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-frontend-voice-validation', 'local-user', 'voice.validation-flow', 'The main frontend flow currently supports importing an audio file, sending it to the backend and viewing transcription plus assistantText.', 'ecosystem:frontend', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-frontend-tool-calls', 'local-user', 'debug.tool-calls', 'Tool Calls remains available as a debug screen, while Facts, Tasks and Settings are outside the active frontend flow in this phase.', 'ecosystem:frontend', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-frontend-design-order', 'local-user', 'roadmap.design-deferred', 'Design work is intentionally deferred until grounded LLM behavior and real database context are validated.', 'ecosystem:frontend', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-voice-endpoint', 'local-user', 'api.voice-endpoint', 'The voice endpoint is POST /api/v1/voice/interactions and accepts multipart/form-data with audio and optional language.', 'ecosystem:voice-stt', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-voice-provider', 'local-user', 'provider.stt-engine', 'Speech to text currently uses a local Vosk-based pipeline with Python and FFmpeg in the backend voice module.', 'ecosystem:voice-stt', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-voice-processing', 'local-user', 'pipeline.audio-processing', 'The backend converts uploaded audio to PCM mono 16k before transcription and returns transcription plus assistantText in the current MVP contract.', 'ecosystem:voice-stt', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-voice-response-contract', 'local-user', 'contracts.response-shape', 'The voice response currently returns transcription, assistantText, audioReplyUrl as null and wakeWordDetected as null.', 'ecosystem:voice-stt', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-llm-endpoint', 'local-user', 'api.llm-generate', 'The LLM endpoint is POST /api/v1/llm/generate and supports dryRun to inspect grounded context without calling an external provider.', 'ecosystem:llm-grounding', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-providers', 'local-user', 'provider.supported-adapters', 'The current LLM module already supports provider abstraction with initial adapters for Gemini and Grok.', 'ecosystem:llm-grounding', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-allowed-sources', 'local-user', 'grounding.allowed-sources', 'In this phase the LLM should ground itself primarily on user_profile and facts, especially facts organized by ecosystem categories.', 'ecosystem:llm-grounding', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-excluded-sources', 'local-user', 'grounding.excluded-sources', 'Tasks and recent conversation turns are intentionally excluded as primary grounding sources in the current phase.', 'ecosystem:llm-grounding', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-insufficient-context', 'local-user', 'grounding.insufficient-context-response', 'When the grounded context is insufficient, the assistant should explicitly say that it did not find enough information in the database to answer safely.', 'ecosystem:llm-grounding', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-llm-dry-run', 'local-user', 'grounding.audit-dry-run', 'Dry run mode is used to inspect which profile fields, facts and ecosystems would be sent as context before any provider call.', 'ecosystem:llm-grounding', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-security-secret-policy', 'local-user', 'security.secret-handling', 'API keys and other secrets must stay out of source control, out of facts, and out of prompt context. Exposed keys should be rotated immediately.', 'ecosystem:security', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-security-prompt-injection', 'local-user', 'security.prompt-injection', 'Persisted facts must be treated as untrusted data and never as executable instructions for the provider.', 'ecosystem:security', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-security-logging', 'local-user', 'security.logging-scope', 'Logs should record metadata such as provider, model, ecosystem slugs and fact counts, but should avoid logging full prompts, raw facts or secrets.', 'ecosystem:security', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-security-context-separation', 'local-user', 'security.context-separation', 'System prompt rules must stay separate from persisted profile and fact content so the provider can distinguish policy from data.', 'ecosystem:security', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),

  ('fact-eco-performance-query-cost', 'local-user', 'performance.grounding-query-shape', 'Grounding should fetch only relevant facts for the requested ecosystems and global preferences instead of scanning the full facts table in memory.', 'ecosystem:performance', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-performance-max-facts', 'local-user', 'performance.max-facts-guideline', 'A practical default for grounded generation is a small fact window such as 12 facts, with a hard cap low enough to protect prompt size and latency.', 'ecosystem:performance', TRUE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-performance-provider-latency', 'local-user', 'performance.provider-latency', 'External provider latency will usually dominate request time after local context assembly is bounded.', 'ecosystem:performance', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z'),
  ('fact-eco-performance-cache-order', 'local-user', 'performance.optimization-order', 'Optimize query selectivity and prompt size before introducing cache complexity.', 'ecosystem:performance', FALSE, '2026-04-03T00:00:00.000Z', '2026-04-03T00:00:00.000Z')
ON CONFLICT(id) DO UPDATE SET
  key = excluded.key,
  value = excluded.value,
  category = excluded.category,
  is_important = excluded.is_important,
  updated_at = excluded.updated_at;
